<script setup>
import { useTemplateRef, watch, nextTick } from 'vue'
import ChatHeader from './ChatHeader.vue'
import ChatInput from './ChatInput.vue'
import MessageBubble from './MessageBubble.vue'

const props = defineProps({
  title: { type: String, required: true },
  subtitle: { type: String, default: '' },
  avatarSrc: { type: String, default: '' },
  online: { type: Boolean, default: false },
  messages: { type: Array, default: () => [] },  // [{id, role, content, timestamp?, status?}]
  inputDisabled: { type: Boolean, default: false },
})
const emit = defineEmits(['send', 'back', 'settings'])

const listRef = useTemplateRef('listRef')

watch(() => props.messages.length, async () => {
  await nextTick()
  listRef.value?.scrollTo({ top: listRef.value.scrollHeight, behavior: 'smooth' })
})
</script>

<template>
  <div class="h-screen flex flex-col bg-akong-paper" data-testid="chat-page">
    <ChatHeader
      :title="title"
      :subtitle="subtitle"
      :avatar-src="avatarSrc"
      :online="online"
      @back="emit('back')"
      @settings="emit('settings')"
    >
      <template #avatar><slot name="avatar"></slot></template>
    </ChatHeader>

    <main ref="listRef" class="flex-1 overflow-y-auto px-3 py-4" data-testid="message-list">
      <slot name="before-messages"></slot>
      <MessageBubble
        v-for="m in messages"
        :key="m.id"
        :role="m.role"
        :content="m.content"
        :timestamp="m.timestamp"
        :status="m.status"
      />
      <slot name="after-messages"></slot>
    </main>

    <ChatInput
      :disabled="inputDisabled"
      @send="(text) => emit('send', text)"
    />
  </div>
</template>
